import React from 'react';
import { useParams } from 'react-router-dom';
import './MembroPerfil.css';

// Importar imagens (você vai adicionar depois)
import bangChanImg from '../assets/images/membros/bang-chan.jpg';

function MembroPerfil() {
  const { nome } = useParams();

  // Dados dos membros - VOCÊ PODE PERSONALIZAR AQUI
  const membrosData = {
    'bang-chan': {
      nome: 'Bang Chan',
      nomeKorean: '방찬',
      foto: bangChanImg,
      posicao: 'Líder, Produtor, Rapper, Vocalista',
      nascimento: '03 de Outubro de 1997',
      nacionalidade: 'Australiano-Coreano',
      altura: '171 cm',
      biografia: `Bang Chan é o líder e produtor principal do Stray Kids. Nascido na Austrália, 
        ele treinou na JYP Entertainment por 7 anos antes de estrear. É conhecido por sua liderança 
        carismática e habilidades incríveis de produção musical.`,
      projetosSolo: [
        'Estrela do programa Stray Kids (Mnet, 2017)',
        'Produtor de todas as músicas do grupo',
        'Chan\'s Room - transmissões ao vivo semanais no V LIVE'
      ],
      musicasSolo: [
        {
          titulo: 'Red Lights',
          colaboracao: 'com Hyunjin',
          ano: 2021,
          link: '#'
        },
        {
          titulo: 'Drive',
          colaboracao: 'SKZ-PLAYER',
          ano: 2023,
          link: '#'
        }
      ],
      redesSociais: {
        instagram: 'https://www.instagram.com/gnabnahc/',
        spotify: '#'
      }
    },
    'changbin': {
      nome: 'Changbin',
      nomeKorean: '창빈',
      foto: bangChanImg, // Trocar pela foto real
      posicao: 'Rapper, Produtor, Vocalista',
      nascimento: '11 de Agosto de 1999',
      nacionalidade: 'Coreano',
      altura: '167 cm',
      biografia: `Changbin é conhecido por seu rap poderoso e habilidades de produção. 
        Membro do 3RACHA ao lado de Bang Chan e Han.`,
      projetosSolo: [
        'Membro do 3RACHA',
        'Diversos covers e performances solo'
      ],
      musicasSolo: [
        {
          titulo: 'Cypher',
          colaboracao: 'SKZ-PLAYER',
          ano: 2022,
          link: '#'
        }
      ],
      redesSociais: {
        instagram: '#',
        spotify: '#'
      }
    },
    'han': {
      nome: 'Han',
      nomeKorean: '한',
      foto: bangChanImg, // Trocar pela foto real
      posicao: 'Rapper, Produtor, Vocalista',
      nascimento: '14 de Setembro de 2000',
      nacionalidade: 'Coreano',
      altura: '169 cm',
      biografia: `Han Jisung é um artista multitalentoso, conhecido por suas letras profundas 
        e versatilidade musical. Membro do 3RACHA.`,
      projetosSolo: [
        'Membro do 3RACHA',
        'Compositor principal do grupo'
      ],
      musicasSolo: [
        {
          titulo: 'Alien',
          colaboracao: 'SKZ-PLAYER',
          ano: 2023,
          link: '#'
        }
      ],
      redesSociais: {
        instagram: '#',
        spotify: '#'
      }
    }
    // ADICIONE OS OUTROS MEMBROS AQUI...
  };

  const membro = membrosData[nome];

  if (!membro) {
    return (
      <div className="container py-5 text-center">
        <h1>Membro não encontrado</h1>
        <a href="/" className="btn btn-success mt-3">Voltar para Home</a>
      </div>
    );
  }

  return (
    <div className="membro-perfil">
      {/* Header com foto de capa */}
      <div className="perfil-header" style={{ backgroundImage: `url(${membro.foto})` }}>
        <div className="perfil-overlay">
          <div className="container">
            <h1 className="perfil-nome">{membro.nome}</h1>
            <p className="perfil-nome-korean">{membro.nomeKorean}</p>
            <p className="perfil-posicao">{membro.posicao}</p>
          </div>
        </div>
      </div>

      {/* Conteúdo */}
      <div className="container py-5">
        <div className="row">
          {/* Coluna Esquerda - Informações Básicas */}
          <div className="col-lg-4 mb-4">
            <div className="card shadow">
              <div className="card-body">
                <h4 className="card-title mb-4">📋 Informações</h4>
                <ul className="list-unstyled">
                  <li className="mb-3">
                    <strong>Data de Nascimento:</strong><br />
                    {membro.nascimento}
                  </li>
                  <li className="mb-3">
                    <strong>Nacionalidade:</strong><br />
                    {membro.nacionalidade}
                  </li>
                  <li className="mb-3">
                    <strong>Altura:</strong><br />
                    {membro.altura}
                  </li>
                </ul>

                {/* Redes Sociais */}
                <hr />
                <h5 className="mb-3">🔗 Redes Sociais</h5>
                <div className="d-flex gap-2">
                  {membro.redesSociais.instagram && (
                    <a href={membro.redesSociais.instagram} target="_blank" rel="noopener noreferrer" className="btn btn-outline-danger btn-sm">
                      Instagram
                    </a>
                  )}
                  {membro.redesSociais.spotify && (
                    <a href={membro.redesSociais.spotify} target="_blank" rel="noopener noreferrer" className="btn btn-outline-success btn-sm">
                      Spotify
                    </a>
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* Coluna Direita - Biografia e Projetos */}
          <div className="col-lg-8">
            {/* Biografia */}
            <div className="card shadow mb-4">
              <div className="card-body">
                <h4 className="card-title mb-3">📖 Biografia</h4>
                <p className="text-muted">{membro.biografia}</p>
              </div>
            </div>

            {/* Projetos Solo */}
            <div className="card shadow mb-4">
              <div className="card-body">
                <h4 className="card-title mb-3">🎬 Projetos Solo</h4>
                <ul>
                  {membro.projetosSolo.map((projeto, index) => (
                    <li key={index} className="mb-2">{projeto}</li>
                  ))}
                </ul>
              </div>
            </div>

            {/* Músicas Solo */}
            <div className="card shadow">
              <div className="card-body">
                <h4 className="card-title mb-4">🎵 Músicas Solo</h4>
                <div className="row g-3">
                  {membro.musicasSolo.map((musica, index) => (
                    <div key={index} className="col-md-6">
                      <div className="card bg-light">
                        <div className="card-body">
                          <h6 className="card-title">{musica.titulo}</h6>
                          <p className="card-text small text-muted mb-2">
                            {musica.colaboracao} • {musica.ano}
                          </p>
                          <a href={musica.link} className="btn btn-sm btn-success">
                            Ouvir 🎧
                          </a>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Botão Voltar */}
        <div className="text-center mt-5">
          <a href="/" className="btn btn-outline-success btn-lg">
            ← Voltar para Home
          </a>
        </div>
      </div>
    </div>
  );
}

export default MembroPerfil;
